export function getChurch(slug: string): Church | undefined {
  return churches.find((c) => c.slug === slug);
}

export function getChurchesByRegion(region: string): Church[] {
  return churches.filter((c) => c.region === region);
}

export function getCitiesForRegion(region: string): string[] {
  const cities = getChurchesByRegion(region).map((c) => c.city);
  return Array.from(new Set(cities));
}

export function getChurchesByCity(region: string, city: string): Church[] {
  return churches.filter((c) => c.region === region && c.city === city);
}

// რეგიონი -> JSON ფაილის სახელი (public/data/-ში), საიდანაც მთელი საქართველოს
// რეესტრის მონაცემები იტვირთება საჭიროებისამებრ (და არა ერთბაშად, ბანდლში)
export const REGION_JSON_FILE: Partial<Record<string, string>> = {
  "კახეთი": "kakheti",
  "მცხეთა-მთიანეთი": "mtskheta-mtianeti",
  "შიდა ქართლი": "shida-kartli",
  "ქვემო ქართლი": "kvemo-kartli",
  "სამცხე-ჯავახეთი": "samtskhe-javakheti",
  "იმერეთი": "imereti",
  "რაჭა-ლეჩხუმი და ქვემო სვანეთი": "racha-lechkhumi",
  "გურია": "guria",
  "აჭარა": "adjara",
  "სამეგრელო-ზემო სვანეთი": "samegrelo-zemo-svaneti",
};

export async function fetchRegionChurches(region: string): Promise<Church[]> {
  const file = REGION_JSON_FILE[region];
  if (!file) return [];
  const res = await fetch(`/data/churches-${file}.json`);
  if (!res.ok) return [];
  return (await res.json()) as Church[];
}

